// @ts-nocheck

const limitTime = 900000; // 15 นาที
const OFFLINE_THRESHOLD = 2; // ต้อง offline 2 รอบติดก่อน trigger

const isMoreThan15Minutes = (ts = 0) => {
    if (!ts) return true;
    const now = Date.now();
    return (now - ts) > limitTime;
};

const normalizaTimestamp = (ts) => {
    let t = Number(ts);
    if (!t) return 0;
    if (t < 1e12) t *= 1000;
    return t;
};

const decodeText = (str = "") => {
    try {
        const cleaned = str.replace(/%(?![0-9A-Fa-f]{2})/g, '%25');
        return decodeURIComponent(cleaned);
    } catch (e) {
        return str;
    }
};

const setup_stream = (conf) => {
    let stream = global.get("xstream") || {};
    let getsetup = global.get("xgetsetup") || {};
    let sysInfo = global.get("xsysinfo") || {};
    let communications = global.get("CheckCommunications") || {};

    const now = Date.now();
    const mac = conf.mac_address;

    let devices = { [mac]: [] };
    let status_acq = { [mac]: {} };
    let obj_info = { [mac]: {} };
    let cate = { [mac]: {} };

    const setup = getsetup[mac]?.setup_data;
    const streamObj = stream[mac]?.stream_data;
    const sys = sysInfo[mac]?.sysinfo_data;

    if (!setup && !streamObj && !sys) {
        return { devices, status_acq, obj_info };
    }

    /* ---------------- CATEGORY ---------------- */
    const ctgs = setup?.setup?.ctgs;
    if (Array.isArray(ctgs)) {
        for (let category of ctgs) {
            const devs = category?.devs || [];
            let cateName = decodeText(category?.term || "");

            for (let devId of devs) {
                cate[mac][devId] = cateName;
            }
        }
    }

    /* ---------------- SYS INFO ---------------- */
    if (sys?.info?.name) {
        obj_info[mac]["name"] = decodeText(sys.info.name);
    }

    /* ---------------- STATUS ---------------- */
    status_acq[mac].xwebpro_on = streamObj?.stream?.acq || 0;

    /* ---------------- INIT COMM ---------------- */
    if (!communications[mac]) {
        communications[mac] = {
            status: false,              // false = ONLINE, true = OFFLINE
            offline_streak: 0,
            offline_count: 0
        };
    }

    /* ---------------- TS CHECK ---------------- */
    const ts = normalizaTimestamp(streamObj?.ts);
    const isOffline = isMoreThan15Minutes(ts);

    /* ---------------- DEBOUNCE ---------------- */
    if (isOffline) {
        communications[mac].offline_streak = Math.min(
            communications[mac].offline_streak + 1,
            OFFLINE_THRESHOLD
        );
    } else {
        communications[mac].offline_streak = 0;
    }

    /* ---------------- STATE MACHINE ---------------- */
    // ONLINE → OFFLINE
    if (
        communications[mac].offline_streak === OFFLINE_THRESHOLD &&
        communications[mac].status === false
    ) {
        communications[mac] = {
            ...communications[mac],
            store_name: conf.xweb_name,
            mac_address: mac,
            device_name: conf.xweb_name,
            alarm_name: "Offline",
            text: "Offline",
            status: true,
            acknow: false,
            dateStart: now,
            offline_count: 0,
            offline_timestamp: null,
        };
    }

    // OFFLINE → ONLINE (Recovery)
    if (
        communications[mac].offline_streak === 0 &&
        communications[mac].status === true
    ) {
        communications[mac].status = false;
    }

    /* ---------------- STREAM DATA ---------------- */
    const streamData = streamObj?.stream?.data;

    if (streamData && typeof streamData === "object") {
        const devicesSetup = setup?.devices || {};

        for (let deviceId in streamData) {
            const device = devicesSetup?.[deviceId];
            if (!device || !device.vrs) continue;

            const devGen = device?.gen || {};
            const adr = devGen.addr2;
            const name = decodeText(devGen.name || "");
            const categoryName = cate[mac][deviceId] || "Others";

            let object = {
                analogInput: [],
                deviceStatus: [],
                alarm: [],
                digitalinput: [],
                outputStatus: [],
                chartDef: [],
            };

            for (let pointId in device.vrs) {
                const point = device.vrs[pointId];
                if (!point || point.vfr !== 1) continue;

                const lng = device?.lng?.vrs?.[pointId];
                if (!lng) continue;

                let group;
                switch (point.vgrp) {
                    case 0: group = "analogInput"; break;
                    case 1: group = "deviceStatus"; break;
                    case 2: group = "alarm"; break;
                    case 3: group = "digitalinput"; break;
                    case 4: group = "outputStatus"; break;
                    default: continue;
                }

                let point_name = decodeText(lng.uvun || lng.vun || "");
                const value = streamData?.[deviceId]?.[pointId] ?? 0;

                if (point.chartDef?.en === true) {
                    object.chartDef.push({
                        pointId,
                        name: point_name,
                        value,
                        index: pointId,
                        unit: point.vudm,
                    });
                }

                object[group].push({
                    pointId,
                    name: point_name,
                    value,
                    unit: point.vudm,
                });
            }

            devices[mac].push({
                name,
                adr,
                cate: categoryName,
                uid: deviceId,
                lanid: devGen.addr1,
                model: devGen.model,
                dbpath: devGen.dbpath,
                analogInput: object.analogInput,
                deviceStatus: object.deviceStatus,
                alarm: object.alarm,
                digitalinput: object.digitalinput,
                outputStatus: object.outputStatus,
                chartDef: object.chartDef,
            });
        }
    }

    global.set("CheckCommunications", communications);

    return { devices, status_acq, obj_info };
};

