    output[mac] = {
        name: compares?.obj_info?.[mac]?.name || conf.xweb_name,
        mac_address: mac,
        on: compares?.status_acq?.[mac]?.xwebpro_on || 0,
        branch_id: conf.branch_id,
        devices: compares?.devices?.[mac] || []
    };
}

msg.payload = output;
return msg;
